function SettingsPage() {
  return (
    <div style={{height:"100%"}}>
      <div
      className="settings-table"
    >
      {/* Левая панель */}
      <div
        style={{
          width: "250px",
          borderRight: "1px solid #ccc",
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          padding: "16px",
        }}
      >
        {/* Аватар */}
        <div
        className="avatar"
        ></div>
        <span style={{ fontSize: "16px", color: "#333", marginBottom: "16px" }}>
          Name
        </span>

        {/* Меню */}
        <div className="menu">
          <button>Просмотр профиля</button>
          <button>Профиль</button>
          <button>Фото</button>
          <button>Безопасность</button>
          <button>Text</button>
          <button style={{color: "red" }}>Выйти</button>
        </div>
      </div>

      {/* Правая часть контента */}
      <div style={{ flex: 1, padding: "16px" }}>
        {/* Контент справа */}
      </div>
    </div>
    </div>
  );
}

export default SettingsPage;
